### TL;DR – What you need to copy

```ocaml
(* blocksci.mli *)
type block = {
  height    : int;
  hash      : string;
  timestamp : float;
  tx_count  : int;
}
val iter_blocks : (block -> unit) -> unit
```

```c
/* blocksci_stubs.c */
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/fail.h>
#include <caml/threads.h>
#include <exception>
#include <string>
#include "blockscicpp.h"          /* <-- real BlockSci header */

/* Convert native BlockSci::Block -> OCaml record */
static value caml_of_block(const BlockSci::Block &blk)
{
  CAMLparam0();
  CAMLlocal1(vblk);
  vblk = caml_alloc(4, 0);
  Store_field(vblk, 0, Val_int(blk.height()));
  Store_field(vblk, 1, caml_copy_string(blk.hash().c_str()));
  Store_field(vblk, 2, caml_copy_double(blk.timestamp()));
  Store_field(vblk, 3, Val_int(blk.tx_count()));
  CAMLreturn(vblk);
}

/* OCaml entry point */
CAMLprim value blocksci_iter_blocks(value cb)
{
  CAMLparam1(cb);
  CAMLlocal1(vblk);

  if (!Is_block(cb))
    caml_invalid_argument("Blocksci.iter_blocks: argument is not a function");

  try {
    BlockSci::BlockIterator it = BlockSci::begin();
    BlockSci::BlockIterator end = BlockSci::end();

    for (; it != end; ++it) {
      vblk = caml_of_block(*it);
      value r = caml_callback_exn(cb, vblk);
      if (Is_exception_result(r)) caml_raise(r);
    }
  }
  catch (const std::exception &e) {
    caml_raise_failure(caml_copy_string(e.what()));
  }
  catch (...) {
    caml_raise_failure(caml_copy_string("Blocksci: unknown C++ exception"));
  }

  CAMLreturn(Val_unit);
}
```

That’s all you need for a clean, exception‑safe OCaml binding that lets users
run arbitrary OCaml code for each block while the underlying C++ iterator walks
the blockchain. Happy hacking!
